# Generated by openai (o3-mini)
# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(accounts, transactions):
    for txn in transactions:
        account = txn.get("account")
        txn_type = txn.get("type")
        amount = txn.get("amount", 0)
        
        if account not in accounts:
            raise ValueError(f"Account '{account}' does not exist.")
        
        if txn_type == "deposit":
            accounts[account] += amount
        elif txn_type == "withdraw":
            if accounts[account] < amount:
                raise ValueError(f"Insufficient funds for account '{account}'.")
            accounts[account] -= amount
        else:
            raise ValueError(f"Unsupported transaction type: {txn_type}")
    
    return accounts

# Example usage
if __name__ == "__main__":
    account_balances = {
        "acc1": 1000,
        "acc2": 1500,
    }
    
    transactions = [
        {"account": "acc1", "type": "deposit", "amount": 200},
        {"account": "acc1", "type": "withdraw", "amount": 300},
        {"account": "acc2", "type": "withdraw", "amount": 500},
        {"account": "acc2", "type": "deposit", "amount": 1000},
    ]
    
    updated_balances = process_transactions(account_balances, transactions)
    print(updated_balances)